mapper.select:
select template_id, template_name, report_type, sections, data_scope, style_config, version_no, status, create_by, create_time, update_by, update_time, remark from nc_report_template
del_flag = '0'
AND template_name like '%' || #{templateName} || '%'
AND report_type = #{reportType}
AND status = #{status}
order by create_time desc, template_id desc

mapper.update:
update nc_report_template
template_name = #{templateName}, report_type = #{reportType}, sections = #{sections}, data_scope = #{dataScope}, style_config = #{styleConfig}, version_no = #{versionNo}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where template_id = #{templateId}

