mapper.select:
select t.task_id, t.task_name, t.template_id, coalesce(p.template_name, t.template_name) as template_name, t.report_period, t.report_scope, t.generate_mode, t.task_status, t.generated_file_name, t.snapshot_content, t.generated_time, t.create_by, t.create_time, t.update_by, t.update_time, t.remark from nc_report_generation_task t left join nc_report_template p on p.template_id = t.template_id
t.del_flag = '0'
AND t.task_name like '%' || #{taskName} || '%'
AND t.task_status = #{taskStatus}
AND t.report_period = #{reportPeriod}
order by t.create_time desc, t.task_id desc

mapper.update:
update nc_report_generation_task
task_name = #{taskName}, template_id = #{templateId}, template_name = #{templateName}, report_period = #{reportPeriod}, report_scope = #{reportScope}, generate_mode = #{generateMode}, task_status = #{taskStatus}, generated_file_name = #{generatedFileName}, snapshot_content = #{snapshotContent}, generated_time = #{generatedTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where task_id = #{taskId}
